15	/// Shared handle passed to the control listener and polled by tray/UI.
16	///
17	/// All fields are cheap to clone (Arc-wrapped).
18	#[derive(Clone)]
19	pub struct DaemonHandle {
20	    pub dispatcher: Arc<Dispatcher>,
21	    /// Set true to suppress audio processing. The pipeline thread checks this
22	    /// on each frame and skips wake/VAD/STT while muted.
23	    pub muted: Arc<AtomicBool>,
24	    /// Name of the currently active profile, updated on every SwitchProfile.
25	    pub active_profile: Arc<RwLock<Option<String>>>,
26	    /// Set true while the wake-word listen window is open (written by coordinator).
27	    pub listening: Arc<AtomicBool>,
28	    /// Set true while PTT is held (written by coordinator).
29	    pub recording: Arc<AtomicBool>,
30	}
31	
32	impl DaemonHandle {
33	    pub fn new(dispatcher: Arc<Dispatcher>) -> Self {
34	        Self {
35	            dispatcher,
36	            muted: Arc::new(AtomicBool::new(false)),
37	            active_profile: Arc::new(RwLock::new(None)),
38	            listening: Arc::new(AtomicBool::new(false)),
39	            recording: Arc::new(AtomicBool::new(false)),
40	        }
41	    }
42	
43	    pub fn state(&self) -> DaemonState {
44	        if self.muted.load(Ordering::Relaxed) {
45	            DaemonState::Muted
46	        } else if self.recording.load(Ordering::Relaxed) {
47	            DaemonState::Recording
48	        } else if self.listening.load(Ordering::Relaxed) {
49	            DaemonState::Listening
50	        } else {
51	            DaemonState::Idle
52	        }
53	    }
54	
55	    pub fn status(&self) -> DaemonStatus {
56	        let macro_count = self.dispatcher.macro_count();
57	        DaemonStatus {
58	            state: self.state(),
59	            active_profile: self.active_profile.read().unwrap().clone(),
60	            macro_count,
61	        }
62	    }
63	}
