174	// Server-side path resolution: uses place_runtime_file, which creates the XDG runtime
175	// directory if it doesn't exist yet. The read-only counterpart lives in control/client.rs.
176	fn get_socket_path() -> Result<PathBuf> {
177	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
178	
179	    xdg.place_runtime_file("vibe-attack.sock")
180	        .context("Failed to place UDS socket in runtime directory")
181	}
