import re, pathlib, sys

missing = []
for path in pathlib.Path("src/control").rglob("*.rs"):
    lines = path.read_text().splitlines()
    for i, line in enumerate(lines):
        stripped = line.strip()
        if not re.match(r'pub\s', stripped):
            continue
        # skip pub use / pub mod / pub type aliases that are trivially self-documenting
        if re.match(r'pub\s+(use|mod)\s', stripped):
            continue
        # look back for a doc comment
        j = i - 1
        while j >= 0 and lines[j].strip() in ('', '{'):
            j -= 1
        if j >= 0 and (lines[j].strip().startswith('///') or lines[j].strip().startswith('//!')):
            continue
        # check attribute lines above
        if j >= 0 and lines[j].strip().startswith('#['):
            k = j - 1
            while k >= 0 and lines[k].strip().startswith('#['):
                k -= 1
            if k >= 0 and (lines[k].strip().startswith('///') or lines[k].strip().startswith('//!')):
                continue
        missing.append(f"{path}:{i+1}: {stripped[:80]}")

if missing:
    print("MISSING DOCS:")
    for m in missing:
        print(" ", m)
    sys.exit(1)
else:
    print("All public items in src/control/ are documented.")
EOF

